// Normalize Moroccan phone → international format 212XXXXXXXXX
const raw = String($input.first().json.phone || '').replace(/\D/g, '');
let phone = raw;
if (raw.startsWith('0') && raw.length === 10) phone = '212' + raw.slice(1);
else if (!raw.startsWith('212') && raw.length === 9) phone = '212' + raw;

return [{
  json: {
    ...$input.first().json,
    phoneNormalized: phone,
    firstName: String($input.first().json.name || '').split(' ')[0],
  }
}];

